def table_name(table_id: str) -> str:
    """Convert table ID to DuckDB-safe table name: e.g. '1.3.1' → '1_3_1_broad_money_m3'"""
    norm_id = table_id.replace(".", "_")
    slug = CATALOG.get(table_id, (table_id.replace(".", "_"), "unknown", table_id))[0]
    return f"{norm_id}_{slug}"


def get_meta(table_id: str) -> dict:
    entry = CATALOG.get(table_id)
    if entry:
        slug, domain, title = entry
    else:
        slug, domain, title = table_id.replace(".", "_"), "unknown", table_id
    return {"table_id": table_id, "slug": slug, "domain": domain, "title": title,
            "table_name": table_name(table_id)}
